package com.scau.dormrepair.common;
import com.scau.dormrepair.config.*;import com.scau.dormrepair.service.*;import com.scau.dormrepair.service.impl.*;import com.zaxxer.hikari.HikariDataSource;import org.apache.ibatis.session.SqlSessionFactory;
public final class AppContext implements AutoCloseable {
private final AppProperties properties;private final HikariDataSource dataSource;private final SqlSessionFactory sqlSessionFactory;private final MyBatisExecutor myBatisExecutor;private final AppSession appSession;private final UserAccountService userAccountService;private final DashboardService dashboardService;private final DormCatalogService dormCatalogService;private final RepairRequestService repairRequestService;private final WorkOrderService workOrderService;private final StatisticsService statisticsService;private final AuditLogService auditLogService;
private AppContext(AppProperties properties,HikariDataSource dataSource,SqlSessionFactory sqlSessionFactory,MyBatisExecutor myBatisExecutor){this.properties=properties;this.dataSource=dataSource;this.sqlSessionFactory=sqlSessionFactory;this.myBatisExecutor=myBatisExecutor;this.appSession=new AppSession();this.userAccountService=new UserAccountServiceImpl(myBatisExecutor,appSession);this.dashboardService=new DashboardServiceImpl(myBatisExecutor);this.dormCatalogService=new DormCatalogServiceImpl(myBatisExecutor,appSession);this.repairRequestService=new RepairRequestServiceImpl(myBatisExecutor);this.workOrderService=new WorkOrderServiceImpl(myBatisExecutor);this.statisticsService=new StatisticsServiceImpl(myBatisExecutor);this.auditLogService=new AuditLogServiceImpl(myBatisExecutor);}
public static AppContext bootstrap(){AppProperties properties=AppProperties.load();HikariDataSource dataSource=DatabaseConfig.createDataSource(properties);SchemaCompatibilitySupport.repair(dataSource);SqlSessionFactory sqlSessionFactory=DatabaseConfig.createSqlSessionFactory(dataSource);MyBatisExecutor myBatisExecutor=new MyBatisExecutor(sqlSessionFactory);return new AppContext(properties,dataSource,sqlSessionFactory,myBatisExecutor);}public AppProperties properties(){return properties;}public SqlSessionFactory sqlSessionFactory(){return sqlSessionFactory;}public AppSession appSession(){return appSession;}public UserAccountService userAccountService(){return userAccountService;}public DashboardService dashboardService(){return dashboardService;}public DormCatalogService dormCatalogService(){return dormCatalogService;}public RepairRequestService repairRequestService(){return repairRequestService;}public WorkOrderService workOrderService(){return workOrderService;}public StatisticsService statisticsService(){return statisticsService;}public AuditLogService auditLogService(){return auditLogService;}@Override public void close(){dataSource.close();}
}